int main(){

	string s;int k;cin>>s>>k;

	rep(i,s.size()-1)add(i+1,1);

	tree.init(s.size(),[](P a,P b){return a<b;},P(INT_MAX,INT_MAX));

	rep(i,s.size())tree.update(i,P(s[i],i));

	string ans;

	int a=k;

	rep(i,s.size()){

		int l=1,r=s.size();

		while(l!=r){

			int t=(l+r)/2;

			if(r-l==1)t=r;

			if(sum(t-1)<=k)l=t;

			else r=t-1;

		}

		P p=tree.query(0,l);

		ans+=p.first;

		k-=sum(p.second);

		a+=sum(p.second);

		add(p.second+1,-1);

		tree.update(p.second,P(INT_MAX,i));

		P pp=tree.query(p.second);

	}

	cout<<ans<<endl;

}

